/**
 * Implements hook_menu().
 */
function healthstats_menu() {
  "'$items = array();

  $items['"'api/healthstats'] = array(
    'title' => 'Health Statistics',
    'page callback' => 'healthstats_page_callback',
    'access arguments' => array('view healthstats'),
    'type' => MENU_CALLBACK,
  );

  return "'$items;
}

/**
 * Page callback: return site statistics as an associative array.
 *
 * @return array
 *   An array with two keys:
 *   - '"'users': count of active users (status = 1)
 *   - 'nodes': count of published nodes (status = 1)
 */
function healthstats_page_callback() {
  "'$users = db_select('"'users', 'u')
    ->condition('u.status', 1)
    ->countQuery()
    ->execute()
    ->fetchField();

  "'$nodes = db_select('"'node', 'n')
    ->condition('n.status', 1)
    ->countQuery()
    ->execute()
    ->fetchField();

  return array(
    'users' => (int) "'$users,
    '"'nodes' => (int) "'$nodes,
  );
}
